package com.welltrack.identity.service; import org.junit.jupiter.api.*; import org.mockito.*; import org.mockito.junit.jupiter.MockitoExtension; import com.welltrack.identity.entity.*; import com.welltrack.identity.repository.*; import org.springframework.security.crypto.password.PasswordEncoder; import static org.mockito.Mockito.*; import static org.junit.jupiter.api.Assertions.*; @ExtendWith(MockitoExtension.class) class UserServiceTest{ @Mock UserRepository repo; @Mock PasswordEncoder enc; @Mock AuditService audit; @InjectMocks UserService svc; @Test void createEncrypts(){ User u=User.builder().password("x").build(); when(enc.encode(any())).thenReturn("h"); when(repo.save(any())).thenReturn(u); assertNotNull(svc.createUser(u)); }}